const series = (context.data && context.data.series) || [];
const links = [];
const nodeSet = {};
series.forEach(fr => {
  const vf = fr.fields.find(f => f.type === 'number');
  if (!vf || !vf.values || !vf.values.length) return;
  const l = vf.labels || {};
  const result = l.result || 'unknown';
  const reason = 'reason: ' + (l.fallback_reason || 'none');
  const v = vf.values[vf.values.length - 1] || 0;
  if (v <= 0) return;
  nodeSet[result] = 1; nodeSet[reason] = 1;
  links.push({ source: result, target: reason, value: v });
});
const nodes = Object.keys(nodeSet).map(n => ({ name: n }));
return {
  backgroundColor: 'transparent',
  tooltip: { trigger: 'item' },
  series: [{
    type: 'sankey', left: 24, right: 140, top: 20, bottom: 20,
    data: nodes, links: links,
    emphasis: { focus: 'adjacency' },
    label: { color: '#ccc' },
    lineStyle: { color: 'gradient', curveness: 0.5 }
  }]
};

const series = (context.data && context.data.series) || [];
const byResult = {};
series.forEach(fr => {
  const vf = fr.fields.find(f => f.type === 'number');
  if (!vf || !vf.values || !vf.values.length) return;
  const l = vf.labels || {};
  const result = l.result || 'unknown';
  const reason = l.fallback_reason || 'none';
  const v = vf.values[vf.values.length - 1] || 0;
  if (v <= 0) return;
  byResult[result] = byResult[result] || {};
  byResult[result][reason] = (byResult[result][reason] || 0) + v;
});
const data = Object.keys(byResult).map(r => ({
  name: r,
  children: Object.keys(byResult[r]).map(rs => ({ name: rs, value: byResult[r][rs] }))
}));
return {
  backgroundColor: 'transparent',
  tooltip: {},
  series: [{ type: 'sunburst', radius: [0, '92%'], data: data,
             label: { rotate: 'radial', color: '#eee', minAngle: 8 } }]
};

