const series = (context.data && context.data.series) || [];
const data = series.map(fr => {
  const vf = fr.fields.find(f => f.type === 'number');
  const l = (vf && vf.labels) || {};
  const v = (vf && vf.values && vf.values.length) ? vf.values[vf.values.length - 1] : 0;
  return { name: l.operation || (vf && vf.name) || '?', value: v };
}).filter(d => d.value > 0);
return {
  backgroundColor: 'transparent',
  tooltip: { formatter: '{b}: {c}' },
  series: [{ type: 'treemap', roam: false, data: data,
             label: { show: true, color: '#fff' },
             levels: [{ itemStyle: { borderColor: '#111', borderWidth: 2, gapWidth: 2 } }] }]
};
